// Look up the ER tap entry for a preset by name (linear scan).
// Returns nullptr if not found.
inline const PresetErTapEntry* findErTapsForPreset(const char* name)
{
    if (!name) return nullptr;
    for (int i = 0; i < kVvPresetErTapCount; ++i)
    {
        const PresetErTapEntry& e = kVvPresetErTaps[i];
        const char* a = name;
        const char* b = e.presetName;
        while (*a && *a == *b) { ++a; ++b; }
        if (*a == 0 && *b == 0) return &e;
    }
    return nullptr;
}

